sp_page.css:
	  section {
	    background-color: $sp-page-bg;
	}
/* Pulse Pharmacy Login Page Override */
.login-page-wrapper,
body {
  background: linear-gradient(135deg, #0F172A 0%, #1E293B 60%, #1a1230 100%) !important;
  min-height: 100vh;
}

.login-page-logo {
  display: block;
  text-align: center;
  font-size: 22px;
  font-weight: 700;
  color: #FFFFFF;
  letter-spacing: -0.3px;
  margin-bottom: 8px;
  font-family: 'Inter', sans-serif;
}

.login-page-logo::before {
  content: '⬤ ';
  color: #E60000;
  font-size: 14px;
}

.login-form-wrapper,
.login-panel,
.panel.login-panel {
  background: #FFFFFF !important;
  border-radius: 16px !important;
  border: none !important;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.4) !important;
  padding: 40px !important;
  max-width: 420px;
  margin: 0 auto;
}

.login-panel .panel-heading {
  background: transparent !important;
  border: none !important;
  text-align: center;
  padding-bottom: 8px;
}

.login-panel .panel-heading h1,
.login-panel .panel-heading h2 {
  font-size: 20px !important;
  font-weight: 700 !important;
  color: #0F172A !important;
}

.login-panel .btn-primary {
  background: #E60000 !important;
  border: none !important;
  border-radius: 8px !important;
  height: 48px !important;
  font-size: 15px !important;
  font-weight: 600 !important;
  width: 100%;
  letter-spacing: 0.1px;
  transition: background 0.2s, box-shadow 0.2s;
}

.login-panel .btn-primary:hover {
  background: #B30000 !important;
  box-shadow: 0 4px 16px rgba(230, 0, 0, 0.35) !important;
}

.login-panel .form-control {
  border: 1.5px solid #E2E8F0 !important;
  border-radius: 8px !important;
  height: 44px !important;
  font-size: 14px !important;
  color: #0F172A !important;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.login-panel .form-control:focus {
  border-color: #E60000 !important;
  box-shadow: 0 0 0 3px rgba(230, 0, 0, 0.12) !important;
}
